import { Component, OnInit } from '@angular/core';
import { AppliancesService } from '../../services/appliances.service';
import { Appliance } from '../../core/data.models';
import { Observable } from 'rxjs';
import { v4 as uuidv4 } from 'uuid';

@Component({
  selector: 'app-appliances-list',
  templateUrl: './appliances-list.component.html'
})
export class AppliancesListComponent implements OnInit {
  appliances$: Observable<Appliance[]>;

  constructor(private svc: AppliancesService) {
    this.appliances$ = this.svc.list$;
  }

  ngOnInit(): void {}

  remove(id: string) {
    this.svc.remove(id);
  }

  seedSample() {
    const sample: Appliance = { id: uuidv4(), name: 'Sample Fridge', brand: 'Acme', model: 'F-100', createdAt: new Date().toISOString() };
    this.svc.add(sample);
  }
}
<div class="header appliances-header">
  <h2>Appliances</h2>
  <div>
    <button class="btn" routerLink="/appliances/new">Add</button>
    <button class="btn" (click)="seedSample()">Seed</button>
  </div>
</div>

<div class="grid">
  <ng-container *ngIf="appliances$ | async as list">
    <div *ngIf="list.length === 0" class="card">No appliances. Click Add to create one.</div>
    <div *ngFor="let a of list" class="card">
      <h3>{{a.name}}</h3>
      <div class="small">{{a.brand}} {{a.model}}</div>
      <div style="margin-top:8px">
        <a [routerLink]="['/appliances', a.id]">View</a>
        <a [routerLink]="['/appliances', a.id, 'edit']" style="margin-left:8px">Edit</a>
        <button style="margin-left:8px" (click)="remove(a.id)">Delete</button>
      </div>
    </div>
  </ng-container>
</div>
